platform_type Fighter WSF_PLATFORM
   icon aircraft
   mover WSF_AIR_MOVER
      maximum_speed 500 m/sec
      minimum_speed 100 m/sec
      default_radial_acceleration 5.0 g
   end_mover
   sensor WSF_RADAR_SENSOR radar
      antenna_pattern radar_pattern
         constant_pattern
            peak_gain 35 db
            azimuth_beamwidth 60 deg
            elevation_beamwidth 60 deg
         end_constant_pattern
      end_antenna_pattern
      update_interval 1.0 sec
      maximum_range 80 nm
      pulse_width 1.0e-6 sec
   end_sensor
   weapon WSF_AIR_TO_AIR_MISSILE aim120
      missile_type WSF_AIR_TO_AIR_MISSILE
      number_of_rounds 4
      range 40 nm
      speed 1200 m/sec
      guidance_type active_radar
   end_weapon
   processor WSF_SCRIPT_PROCESSOR engage_logic
      script_variables 
         extern double TIME_NOW;
         extern WsfPlatform SELF;
         WsfPlatform target;
      end_script_variables
      on_initialize
         print("Processor initialized for " + SELF.Name());
      end_on_initialize
      on_update
         # simple engagement logic: look for enemy in tracks, fire when in range
         WsfSensor mySensor = SELF.Sensor("radar");
         if (mySensor.IsNull() || !mySensor.IsOn()) {
            return;
         }
         int trackCount = mySensor.TrackCount();
         if (trackCount <= 0) {
            return;
         }
         double closestRange = 999999.0;
         WsfTrack bestTrack;
         for (int i = 0; i < trackCount; i = i + 1) {
            WsfTrack trk = mySensor.TrackEntry(i);
            if (trk.IsValid() && trk.Target().IsValid() && trk.Target().Side() != SELF.Side()) {
               double rng = SELF.SlantRangeTo(trk.Target());
               if (rng < closestRange) {
                  closestRange = rng;
                  bestTrack = trk;
               }
            }
         }
         if (bestTrack.IsValid()) {
            if (closestRange < 40 nm) {
               WsfWeapon wpn = SELF.Weapon("aim120");
               if (wpn.IsValid() && wpn.RoundsRemaining() > 0) {
                  wpn.FireAtTrack(bestTrack);
                  print(SELF.Name() + " fired AIM-120 at " + bestTrack.TargetName());
               }
            } else {
               # approach target: set heading toward him
               WsfGeoPoint myPos = SELF.Position();
               WsfGeoPoint tgtPos = bestTrack.Target().Position();
               double hdg = myPos.BearingTo(tgtPos);
               SELF.Mover().SetHeadingCommand(hdg);
               SELF.Mover().SetSpeedCommand(400 m/sec);
            }
         }
      end_on_update
   end_processor
end_platform_type

task EngageEnemy
   script
      writeln("Task: Engage enemy aircraft");
   end_script
end_task

platform blue_1 Fighter
   side blue
   position 35.0n 120.0w altitude 30000 ft msl
   route
      position 35.0n 120.0w altitude 30000 ft msl speed 300 m/sec heading 0 deg
      position 36.0n 120.0w altitude 30000 ft msl speed 300 m/sec
   end_route
   task EngageEnemy
end_platform

